pratica_guiada.python:
# Classificação de alerta de queimada — INPE
bioma = input("Bioma (amazonia/cerrado/outros): ").lower()
focos_detectados = int(input("Focos detectados no dia: "))

if focos_detectados > 0:
    print(f"Focos registrados: {focos_detectados}")
    if bioma == "amazonia":
        if focos_detectados >= 50:
            print("ALERTA: CRÍTICO — Amazônia em emergência")
        elif focos_detectados >= 20:
            print("ALERTA: ALTO — monitoramento intensivo")
        else:
            print("ALERTA: MODERADO — monitoramento regular")
    elif bioma == "cerrado":
        if focos_detectados >= 100:
            print("ALERTA: CRÍTICO — Cerrado em colapso")
        else:
            print("ALERTA: ATENÇÃO — Cerrado em situação sensível")
    else:
        print("ALERTA: REGISTRADO — protocolo padrão ativado")
else:
    print("Sem focos detectados hoje — situação normal")
